import{_ as r,c as s,o as n,ag as o,j as e,a as t}from"./chunks/framework.C_7JoTpM.js";const p="/2025-Team-Epibot-Docs/images/mechanic_images/week4/emplacement_roulement.png",l="/2025-Team-Epibot-Docs/images/mechanic_images/week4/port_capteurs_parts.png",c="/2025-Team-Epibot-Docs/images/mechanic_images/week4/separation_demarquation.png",d="/2025-Team-Epibot-Docs/images/mechanic_images/week4/mise_en_plan_1.png",u="/2025-Team-Epibot-Docs/images/mechanic_images/week4/mise_en_plan_2.png",h="/2025-Team-Epibot-Docs/images/mechanic_images/week4/mise_en_plan_3.png",m="/2025-Team-Epibot-Docs/images/mechanic_images/week4/material.jpg",g="/2025-Team-Epibot-Docs/images/mechanic_images/week4/roulement_fixing.jpg",b="/2025-Team-Epibot-Docs/images/mechanic_images/week4/montage_verti-horrizontal_2.jpg",i="/2025-Team-Epibot-Docs/images/mechanic_images/week4/poulie_fixing.jpg",y="/2025-Team-Epibot-Docs/images/mechanic_images/week4/second_face.jpg",f="/2025-Team-Epibot-Docs/images/mechanic_images/week4/poulie_fixing_2.jpg",_="/2025-Team-Epibot-Docs/images/mechanic_images/week4/decoupe.jpg",w="/2025-Team-Epibot-Docs/images/mechanic_images/week4/tapis_picking.jpg",C=JSON.parse('{"title":"⚙️ Physical Construction Phase","description":"","frontmatter":{},"headers":[],"relativePath":"week4/pole-mecanic/Mechanic.md","filePath":"week4/pole-mecanic/Mechanic.md"}'),v={name:"week4/pole-mecanic/Mechanic.md"};function q(T,a,D,A,k,x){return n(),s("div",null,a[0]||(a[0]=[o('<h2 id="mechanical-design-documentation-–-autonomous-conveyor-system" tabindex="-1"><span style="color:#08C5D1;">## Mechanical Design Documentation – Autonomous Conveyor System</span> <a class="header-anchor" href="#mechanical-design-documentation-–-autonomous-conveyor-system" aria-label="Permalink to &quot;&lt;span style=&quot;color: #08C5D1;&quot;&gt;## Mechanical Design Documentation – Autonomous Conveyor System&lt;/span&gt;&quot;">​</a></h2><h3 id="project-context" tabindex="-1"><span style="color:#9AC8EB;">Project Context</span> <a class="header-anchor" href="#project-context" aria-label="Permalink to &quot;&lt;span style=&quot;color: #9AC8EB;&quot;&gt;Project Context&lt;/span&gt;&quot;">​</a></h3><p>The objective of this challenge is to bring together all the skills acquired during previous projects to design and build an <code>**autonomous, intelligent, and efficient conveyor system**</code>.</p><p>To achieve this, our multidisciplinary team collaborated to produce sketches and diagrams envisioning the conveyor. The conveyor’s main dimensions are:</p><ul><li><strong>Length:</strong> 650 mm</li><li><strong>Height of belt from floor:</strong> 100 mm</li></ul><p>The design process followed <strong>two key phases</strong>:</p><ol><li><strong>Virtual Design</strong> — conceptualizing and modeling our components in CAD.</li><li><strong>Physical Design</strong> — preparing for real-world fabrication and assembly.</li></ol><p>This document details the mechanical conception process, the constraints we encountered, and how we solved them.</p><hr><h2 id="🖥️-virtual-design" tabindex="-1"><span style="color:#08C5D1;">## 🖥️ Virtual Design</span> <a class="header-anchor" href="#🖥️-virtual-design" aria-label="Permalink to &quot;&lt;span style=&quot;color: #08C5D1;&quot;&gt;## 🖥️ Virtual Design&lt;/span&gt;&quot;">​</a></h2>',10),e("iframe",{src:"https://player.vimeo.com/video/1100264151?badge=0&autopause=0&player_id=0&app_id=58479",frameborder:"0",allow:"autoplay; fullscreen; picture-in-picture; clipboard-write; encrypted-media; web-share",style:{width:"100%",height:"300px"},title:"vue-3d-convoyeur"},null,-1),e("p",null,[t("The virtual design work primarily involved "),e("strong",null,"SolidWorks"),t(" for 3D modeling, and "),e("strong",null,"Illustrator"),t(" for preparing sketches intended for laser cutting.")],-1),e("p",null,"Below is an overview of the mechanical components and the reasoning behind each design decision.",-1),e("hr",null,null,-1),e("h3",{id:"🔩-vertical-support",tabindex:"-1"},[e("span",{style:{color:"#9AC8EB"}},"🔩 Vertical Support"),t(),e("a",{class:"header-anchor",href:"#🔩-vertical-support","aria-label":'Permalink to "<span style="color: #9AC8EB;">🔩 Vertical Support</span>"'},"​")],-1),e("iframe",{src:"https://player.vimeo.com/video/1100264624?badge=0&autopause=0&player_id=0&app_id=58479",width:"100%",height:"300px",frameborder:"0",allow:"autoplay; fullscreen; picture-in-picture; clipboard-write; encrypted-media; web-share",title:"vue-support-verticale-3d"},null,-1),o('<ul><li><p>This is the <strong>main vertical plate</strong> supporting the entire conveyor structure.</p></li><li><p><strong>Dimensions:</strong></p><ul><li>Length: 650 mm (65 cm)</li><li>Height: 110 mm (11 cm)</li></ul></li></ul><blockquote><p>We deliberately designed it 10 mm higher than the required 100 mm to maintain a small safety margin.</p></blockquote><h4 id="features" tabindex="-1"><span style="color:#DB6A8F;padding-left:8px;"> Features: </span> <a class="header-anchor" href="#features" aria-label="Permalink to &quot;&lt;span style=&quot;color: #DB6A8F; padding-left: 8px;&quot;&gt; Features: &lt;/span&gt;&quot;">​</a></h4><ul><li><strong>Two rows of small cavities</strong> to mount the horizontal supports.</li><li><strong>Circular holes (30 mm diameter)</strong> at each end to fit bearings, allowing smooth rotation of the drum shaft.</li></ul><p><img src="'+p+'" alt="emplacement_roulement"></p><blockquote><p>Many additional cavities serve mainly decorative purposes and to reduce weight.</p></blockquote><p><strong>Important Note:</strong></p><ul><li>The motor mounting location was updated <strong>after</strong> the initial video capture. The final position was based on the actual dimensions of the Nema 17 stepper motor we procured.</li></ul><p><strong>Design Process</strong></p>',9),e("iframe",{src:"https://player.vimeo.com/video/1100264079?title=0&byline=0&portrait=0&badge=0&autopause=0&player_id=0&app_id=58479",frameborder:"0",allow:"autoplay; fullscreen; picture-in-picture; clipboard-write; encrypted-media; web-share",style:{top:"0",left:"0",width:"100%",height:"300px"},title:"support-de-face-conception"},null,-1),e("hr",null,null,-1),e("h3",{id:"🔧-horizontal-supports",tabindex:"-1"},[e("span",{style:{color:"#9AC8EB"}},"🔧 Horizontal Supports"),t(),e("a",{class:"header-anchor",href:"#🔧-horizontal-supports","aria-label":'Permalink to "<span style="color: #9AC8EB;">🔧 Horizontal Supports</span>"'},"​")],-1),e("iframe",{src:"https://player.vimeo.com/video/1100266127?title=0&byline=0&portrait=0&badge=0&autopause=0&player_id=0&app_id=58479",frameborder:"0",allow:"autoplay; fullscreen; picture-in-picture; clipboard-write; encrypted-media; web-share",style:{top:"0",left:"0",width:"100%",height:"300px"},title:"vue-support-horizontal-3d"},null,-1),o('<ul><li>Two horizontal plates positioned into the rows of cavities on the vertical supports.</li><li>They run <strong>perpendicular</strong> to the vertical plates and ensure the entire structure stays balanced.</li></ul><h4 id="purpose" tabindex="-1"><span style="color:#DB6A8F;padding-left:8px;"> Purpose: </span> <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;&lt;span style=&quot;color: #DB6A8F; padding-left: 8px;&quot;&gt; Purpose: &lt;/span&gt;&quot;">​</a></h4><ul><li>Provide stability to the conveyor belt, especially if it needs to carry heavy loads.</li><li>Help prevent overflow or jamming of transported items.</li></ul><blockquote><p>The horizontal supports straddle the drum, making it easier to deploy the belt over them.</p></blockquote><h4 id="dimensions" tabindex="-1"><span style="color:#DB6A8F;padding-left:8px;"> Dimensions:</span> <a class="header-anchor" href="#dimensions" aria-label="Permalink to &quot;&lt;span style=&quot;color: #DB6A8F; padding-left: 8px;&quot;&gt; Dimensions:&lt;/span&gt;&quot;">​</a></h4><ul><li><p><strong>Spacing between plates:</strong> 70 mm</p></li><li><p><strong>Width of each plate:</strong> 70 + (2 × 40) mm = 150 mm</p><ul><li>The extra 40 mm per side accounts for the interlocking features.</li></ul></li><li><p><strong>Length:</strong> 590 mm</p></li></ul><p><strong>Design Process</strong></p>',7),e("iframe",{src:"https://player.vimeo.com/video/1100264115?title=0&byline=0&portrait=0&badge=0&autopause=0&player_id=0&app_id=58479",frameborder:"0",allow:"autoplay; fullscreen; picture-in-picture; clipboard-write; encrypted-media; web-share",style:{top:"0",left:"0",width:"100%",height:"300px"},title:"support-horrizontal-design-process"},null,-1),e("hr",null,null,-1),e("h3",{id:"🥁-drum",tabindex:"-1"},[e("span",{style:{color:"#9AC8EB"}},"🥁 Drum"),t(),e("a",{class:"header-anchor",href:"#🥁-drum","aria-label":'Permalink to "<span style="color: #9AC8EB;">🥁 Drum</span>"'},"​")],-1),e("iframe",{src:"https://player.vimeo.com/video/1100264137?title=0&byline=0&portrait=0&badge=0&autopause=0&player_id=0&app_id=58479",frameborder:"0",allow:"autoplay; fullscreen; picture-in-picture; clipboard-write; encrypted-media; web-share",style:{top:"0",left:"0",width:"100%",height:"300px"},title:"tambour-vue-3d"},null,-1),o('<ul><li>Cylindrical part directly in contact with the conveyor belt, transmitting motion.</li></ul><h4 id="features-1" tabindex="-1"><span style="color:#DB6A8F;padding-left:8px;"> Features:</span> <a class="header-anchor" href="#features-1" aria-label="Permalink to &quot;&lt;span style=&quot;color: #DB6A8F; padding-left: 8px;&quot;&gt; Features:&lt;/span&gt;&quot;">​</a></h4><ul><li><p>Both drum ends are designed to fit into bearings mounted in the vertical supports.</p></li><li><p>One drum end has an extended shaft (<strong>23 mm vs. 15 mm</strong>) to:</p><ul><li>Pass through the thicker vertical plate.</li><li>Accommodate a pulley that transmits rotation from the motor.</li></ul></li></ul><p><img src="'+l+'" alt=" drum protruding through vertical plate"></p><p><strong>Design Process</strong></p><hr><h3 id="⛓️-pulley-system" tabindex="-1"><span style="color:#9AC8EB;">⛓️ Pulley System</span> <a class="header-anchor" href="#⛓️-pulley-system" aria-label="Permalink to &quot;&lt;span style=&quot;color: #9AC8EB;&quot;&gt;⛓️ Pulley System&lt;/span&gt;&quot;">​</a></h3>',7),e("iframe",{src:"https://player.vimeo.com/video/1100264175?title=0&byline=0&portrait=0&badge=0&autopause=0&player_id=0&app_id=58479",frameborder:"0",allow:"autoplay; fullscreen; picture-in-picture; clipboard-write; encrypted-media; web-share",style:{top:"0",left:"0",width:"100%",height:"300px"},title:"vue-poulie-3d"},null,-1),o('<h4 id="objective" tabindex="-1"><span style="color:#DB6A8F;padding-left:8px;"> Objective:</span> <a class="header-anchor" href="#objective" aria-label="Permalink to &quot;&lt;span style=&quot;color: #DB6A8F; padding-left: 8px;&quot;&gt; Objective:&lt;/span&gt;&quot;">​</a></h4><p>To transmit motion from the <strong>Nema 17 stepper motor</strong> to the drum.</p><ul><li>We explored several transmission methods. The following video was a valuable reference: <a href="https://www.youtube.com/watch?v=5Xn26kxmX5U" target="_blank" rel="noreferrer">YouTube Video on Pulley Systems</a></li></ul><h4 id="solution" tabindex="-1"><span style="color:#DB6A8F;padding-left:8px;"> Solution: </span> <a class="header-anchor" href="#solution" aria-label="Permalink to &quot;&lt;span style=&quot;color: #DB6A8F; padding-left: 8px;&quot;&gt; Solution: &lt;/span&gt;&quot;">​</a></h4><ul><li>We chose a <strong>belt and pulley system.</strong></li><li>Since we couldn’t source custom belts of precise lengths, we decided to use <strong>elastic bands</strong> as belts.</li></ul><p><strong>Elastic Band Specifications:</strong></p><ul><li>Length: 100 mm</li><li>Width: 1 mm</li><li>Height: 1 mm</li></ul><h4 id="pulley-details" tabindex="-1"><span style="color:#DB6A8F;padding-left:8px;"> Pulley Details:</span> <a class="header-anchor" href="#pulley-details" aria-label="Permalink to &quot;&lt;span style=&quot;color: #DB6A8F; padding-left: 8px;&quot;&gt; Pulley Details:&lt;/span&gt;&quot;">​</a></h4><ul><li><p>Two pulleys were designed:</p><ul><li>One with a 5 mm axial hole (fits the motor shaft).</li><li>One with a 10 mm axial hole (fits the drum shaft).</li></ul></li></ul><blockquote><p>The pulleys were specifically modeled to hold multiple elastic bands for better grip and reliability.</p></blockquote><hr><h3 id="🎯-sensor-supports" tabindex="-1"><span style="color:#9AC8EB;">🎯 Sensor Supports</span> <a class="header-anchor" href="#🎯-sensor-supports" aria-label="Permalink to &quot;&lt;span style=&quot;color: #9AC8EB;&quot;&gt;🎯 Sensor Supports&lt;/span&gt;&quot;">​</a></h3>',12),e("iframe",{src:"https://player.vimeo.com/video/1100264058?title=0&byline=0&portrait=0&badge=0&autopause=0&player_id=0&app_id=58479",frameborder:"0",allow:"autoplay; fullscreen; picture-in-picture; clipboard-write; encrypted-media; web-share",style:{top:"0",left:"0",width:"100%",height:"300px"},title:"port-capteur-vue-3d"},null,-1),o('<p>We designed a dedicated structure to hold:</p><ul><li>A <strong>color sensor</strong> (TCS34725)</li><li>A <strong>presence detector</strong> (KY-008)</li></ul><h4 id="design" tabindex="-1"><span style="color:#DB6A8F;padding-left:8px;"> Design:</span> <a class="header-anchor" href="#design" aria-label="Permalink to &quot;&lt;span style=&quot;color: #DB6A8F; padding-left: 8px;&quot;&gt; Design:&lt;/span&gt;&quot;">​</a></h4><ul><li>A surface parallel to the conveyor belt for mounting the color sensor.</li><li>A vertical surface perpendicular to the belt for mounting the KY-008 presence sensor.</li><li>Both surfaces are supported by a bent bar attached to one of the horizontal plates.</li></ul><p><img src="'+l+'" alt="Images of sensor components and mounts"></p><p><strong>Design Process</strong></p>',6),e("iframe",{src:"https://player.vimeo.com/video/1100264021?title=0&byline=0&portrait=0&badge=0&autopause=0&player_id=0&app_id=58479",frameborder:"0",allow:"autoplay; fullscreen; picture-in-picture; clipboard-write; encrypted-media; web-share",style:{top:"0",left:"0",width:"100%"},title:"port-capteur-3D"},null,-1),e("hr",null,null,-1),e("h2",{id:"🛠️-assembly-in-solidworks",tabindex:"-1"},[e("span",{style:{color:"#08C5D1"}},"## 🛠️ Assembly in SolidWorks"),t(),e("a",{class:"header-anchor",href:"#🛠️-assembly-in-solidworks","aria-label":'Permalink to "<span style="color: #08C5D1;">## 🛠️ Assembly in SolidWorks</span>"'},"​")],-1),e("iframe",{src:"https://player.vimeo.com/video/1100263974?title=0&byline=0&portrait=0&badge=0&autopause=0&player_id=0&app_id=58479",frameborder:"0",allow:"autoplay; fullscreen; picture-in-picture; clipboard-write; encrypted-media; web-share",style:{top:"0",left:"0",width:"100%",height:"300px"},title:"assemblage-video-solid-works"},null,-1),o('<p>To create an accurate virtual assembly, we imported:</p><ul><li>A <strong>Nema 17 stepper motor</strong> model (downloaded from <a href="https://grabcad.com/" target="_blank" rel="noreferrer">GrabCAD</a>).</li><li>A <strong>KY-008 laser sensor.</strong></li><li>A <strong>TCS34725 color sensor.</strong> This ensured our virtual model closely represents the real mechanical constraints and space requirements.</li></ul><p><a href="/2025-Team-Epibot-Docs/images/mechanic_images/week4/conveyor_virtual_design.zip">Download All SolidWorks Files and Assets</a></p><hr><h2 id="📂-download-all-components" tabindex="-1"><span style="color:#08C5D1;">## 📂 Download All Components</span> <a class="header-anchor" href="#📂-download-all-components" aria-label="Permalink to &quot;&lt;span style=&quot;color: #08C5D1;&quot;&gt;## 📂 Download All Components&lt;/span&gt;&quot;">​</a></h2><h1 id="⚙️-physical-construction-phase" tabindex="-1">⚙️ Physical Construction Phase <a class="header-anchor" href="#⚙️-physical-construction-phase" aria-label="Permalink to &quot;⚙️ Physical Construction Phase&quot;">​</a></h1><hr><h2 id="✅-obtaining-the-parts" tabindex="-1"><span style="color:#08C5D1;">## ✅ Obtaining the Parts</span> <a class="header-anchor" href="#✅-obtaining-the-parts" aria-label="Permalink to &quot;&lt;span style=&quot;color: #08C5D1;&quot;&gt;## ✅ Obtaining the Parts&lt;/span&gt;&quot;">​</a></h2><h3 id="_3d-printing" tabindex="-1"><span style="color:#9AC8EB;">3D Printing</span> <a class="header-anchor" href="#_3d-printing" aria-label="Permalink to &quot;&lt;span style=&quot;color: #9AC8EB;&quot;&gt;3D Printing&lt;/span&gt;&quot;">​</a></h3><p>At this stage, we already had all the CAD files and parts designed. Components like the sensor bracket, the drum, and the pulleys were 3D-printed using PLA material because they are small-sized parts.</p><p>The workflow was as follows:</p><ul><li>Convert SolidWorks files to <code>.stl</code> format.</li><li>Import the <code>.stl</code> files into <strong>PrusaSlicer</strong>.</li><li>Generate the G-code.</li><li>Transfer the G-code to the 3D printer.</li></ul><hr><h3 id="laser-cutting" tabindex="-1"><span style="color:#9AC8EB;">### Laser Cutting </span> <a class="header-anchor" href="#laser-cutting" aria-label="Permalink to &quot;&lt;span style=&quot;color: #9AC8EB;&quot;&gt;###  Laser Cutting &lt;/span&gt;&quot;">​</a></h3><p>The vertical and horizontal panels were too long to print or fit into standard laser-cutting machines. One challenge was that the working area of our laser cutter was limited to about <strong>60 × 30 cm</strong>, while our vertical supports were designed to be 65 cm long.</p><h4 id="design-adaptations" tabindex="-1"><span style="color:#DB6A8F;padding-left:8px;"> Design Adaptations</span> <a class="header-anchor" href="#design-adaptations" aria-label="Permalink to &quot;&lt;span style=&quot;color: #DB6A8F; padding-left: 8px;&quot;&gt; Design Adaptations&lt;/span&gt;&quot;">​</a></h4><p>To overcome this, we modified our design:</p><ul><li><p>We <strong>split the motor zone from the rest of the conveyor</strong> and connected them horizontally with a new support plate.</p><p><img src="'+c+'" alt="Screenshot showing separation and demarcation"></p></li><li><p>We created a <strong>new motor zone</strong> to house the motor separately.</p></li></ul>',18),e("iframe",{src:"https://player.vimeo.com/video/1100824407?badge=0&autopause=0&player_id=0&app_id=58479",frameborder:"0",allow:"autoplay; fullscreen; picture-in-picture; clipboard-write; encrypted-media; web-share",style:{top:"0",left:"0",width:"100%",height:"300px"},title:"création de la zone motrice"},null,-1),e("ul",null,[e("li",null,[t("We designed a "),e("strong",null,"basal support structure"),t(" capable of holding the entire assembly. We also made adjustments to the dimensions to ensure the final length still reached "),e("strong",null,"650 mm"),t(".")])],-1),e("iframe",{src:"https://player.vimeo.com/video/1100824443?title=0&byline=0&portrait=0&badge=0&autopause=0&player_id=0&app_id=58479",frameborder:"0",allow:"autoplay; fullscreen; picture-in-picture; clipboard-write; encrypted-media; web-share",style:{top:"0",left:"0",width:"100%",height:"300px%"},title:"support_basale"},null,-1),e("p",null,"After these changes, we updated the assembly in SolidWorks, which resulted in the following view:",-1),e("iframe",{src:"https://player.vimeo.com/video/1100825538?badge=0&autopause=0&player_id=0&app_id=58479",frameborder:"0",allow:"autoplay; fullscreen; picture-in-picture; clipboard-write; encrypted-media; web-share",style:{top:"0",left:"0",width:"100%"},title:"vue_assembly_modificated"},null,-1),o('<hr><h2 id="✂️-laser-cutting-workflow" tabindex="-1"><span style="color:#08C5D1;">## ✂️ Laser Cutting Workflow</span> <a class="header-anchor" href="#✂️-laser-cutting-workflow" aria-label="Permalink to &quot;&lt;span style=&quot;color: #08C5D1;&quot;&gt;## ✂️ Laser Cutting Workflow&lt;/span&gt;&quot;">​</a></h2><p>To prepare for laser cutting, we:</p><ul><li>Opened the <strong>technical drawings (mise en plan)</strong> of the parts.</li><li>Exported them in <strong>SVG format</strong>.</li><li>Configured the laser cutting parameters using <strong>Adobe Illustrator</strong>.</li></ul><p>Here are some screenshots from this process:</p><ul><li><img src="'+d+'" alt="Mise en plan 1 screenshot"></li><li><img src="'+u+'" alt="Mise en plan 2 screenshot"></li><li><img src="'+h+'" alt="Mise en plan 3 screenshot"></li></ul><p>All the files used for laser cutting are available for download in the folder laser_cutting_plans.</p><p>Once the files were ready, we proceeded with the cutting and 3D printing of all the necessary parts.</p><p><img src="'+m+'" alt="Images of obtained materials"></p><hr><h2 id="🔧-assembly-process" tabindex="-1"><span style="color:#08C5D1;">## 🔧 Assembly Process</span> <a class="header-anchor" href="#🔧-assembly-process" aria-label="Permalink to &quot;&lt;span style=&quot;color: #08C5D1;&quot;&gt;## 🔧 Assembly Process&lt;/span&gt;&quot;">​</a></h2><p>Once we had all the components, we started assembling the conveyor. Here’s a step-by-step summary of the process:</p><ul><li><p><strong>Insertion of the four bearings</strong> into their dedicated slots.<br><img src="'+g+'" alt="Screenshot showing bearing insertion"></p></li><li><p><strong>Mounting the two horizontal supports</strong> into the rows of cavities on the vertical supports. <img src="'+b+'" alt="Screenshot showing horizontal supports installation"></p></li><li><p><strong>Inserting the drums</strong> into the bearing axes.<br><img src="'+i+'" alt="Screenshot showing drum insertion"></p></li><li><p><strong>Placing the second vertical face</strong> on top of the assembly.<br><img src="'+y+'" alt="Screenshot showing second vertical panel assembly"></p></li><li><p><strong>Inserting the pulleys</strong> onto the motor and drum shafts.<br><img src="'+i+'" alt="Screenshot showing pulley insertion"></p><p><img src="'+f+'" alt="Screenshot showing pulley insertion"></p></li><li><p><strong>Fixing the NEMA 17 motor</strong> and the basal horizontal support.</p></li><li><p><strong>Cutting the conveyor belt:</strong></p><ul><li>We used a <strong>1.2 × 0.065 m leather sheet</strong> (the same material typically used in upholstery).</li><li>The belt was placed over the drums and its ends were glued together to form the loop.</li></ul><p><img src="'+_+'" alt="Screenshot of belt cutting"></p><p><img src="'+w+'" alt="Screenshot of belt after cutting and gluing"></p></li><li><p><strong>Attaching the sensors</strong> to the sensor bracket.</p></li><li><p><strong>Fixing the sensor bracket</strong> to the vertical support.</p></li></ul><hr>',14)]))}const S=r(v,[["render",q]]);export{C as __pageData,S as default};
